/**
 * @summary Submit a deposit (announcer)
 */
export const getCreateDepositUrl = () => {
  return `/api/deposits`;
};

export const createDeposit = async (
  createDepositInput: CreateDepositInput,
  options?: RequestInit,
): Promise<Deposit> => {
  const formData = new FormData();
  formData.append(`link`, createDepositInput.link);
  formData.append(`platform`, createDepositInput.platform);
  formData.append(`taskType`, createDepositInput.taskType);
  formData.append(`durationDays`, createDepositInput.durationDays.toString());

  return customFetch<Deposit>(getCreateDepositUrl(), {
    ...options,
    method: "POST",
    body: formData,
  });
};

